    .from(gatewayInstallations)
    .where(
      and(
        eq(gatewayInstallations.provider, "github"),
        isNull(gatewayInstallations.providerOrgId)
      )
    );

  console.log(`Found ${installations.length} GitHub installations to backfill`);

  const jwt = await createGitHubAppJWT(config);

  for (const inst of installations) {
    try {
      const response = await fetch(
        `https://api.github.com/app/installations/${inst.externalId}`,
