            set: {
              status: "active",
              connectedBy,
              orgId,
              providerAccountInfo: accountInfo,
              providerOrgId: orgInfo.orgId,
              providerOrgLogin: orgInfo.orgLogin,
              updatedAt: new Date().toISOString(),
            },
          })
          .returning({ id: gatewayInstallations.id });

        const installation = rows[0];
        if (!installation) {
          throw new Error("upsert_failed");
        }
        installationId = installation.id;
      }
    } else {
      // Non-GitHub provider — standard upsert without org constraint
      const existingRows = await db
        .select({ id: gatewayInstallations.id })
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.provider, providerName),
            eq(gatewayInstallations.externalId, result.externalId)
          )
        )
        .limit(1);

      reactivated = existingRows.length > 0;

      const rows = await db
        .insert(gatewayInstallations)
        .values({
          provider: providerName,
          externalId: result.externalId,
          connectedBy,
          orgId,
          status: "active",
          providerAccountInfo: accountInfo,
        })
        .onConflictDoUpdate({
          target: [
            gatewayInstallations.provider,
            gatewayInstallations.externalId,
          ],
          set: {
            status: "active",
            connectedBy,
            orgId,
            providerAccountInfo: accountInfo,
            updatedAt: new Date().toISOString(),
          },
        })
        .returning({ id: gatewayInstallations.id });

      const installation = rows[0];
      if (!installation) {
        throw new Error("upsert_failed");
      }
      installationId = installation.id;
    }

    const installation = { id: installationId };
```

#### 4. Update the stateless callback path

**File**: `api/platform/src/lib/oauth/callback.ts`
**Changes**: The stateless callback handler at lines 174-205 reconstructs `stateData` from the existing installation row. No changes needed here — the stateless path is for reinstallation/permission-change events that arrive without state. The row already exists, so the upsert will take the `existingRow && existingRow.orgId === orgId` branch (reinstatement).

No code changes needed for this — just noting it's already handled.

### Success Criteria:

#### Automated Verification:

- [ ] `pnpm typecheck` passes
- [ ] `pnpm check` passes
- [ ] `pnpm build:platform` succeeds

#### Manual Verification:

- [ ] Connect a GitHub org to a Lightfast workspace → `providerOrgId` and `providerOrgLogin` are written to the installation row (verify in DB studio)
- [ ] Attempt to connect the **same** GitHub org to a **different** Lightfast workspace → callback returns error "This GitHub organization is already connected to another Lightfast workspace", user sees error page
- [ ] Revoke a GitHub connection (set `status = "revoked"`), then re-install the GitHub App on the **same** Lightfast org → reinstates the connection with the new installation ID, row keeps the same `providerOrgId`
- [ ] Non-GitHub provider connections (Vercel, Linear) still work normally (upsert path unchanged)

**Implementation Note**: After completing this phase and all automated verification passes, pause here for manual confirmation from the human that the manual testing was successful before proceeding to the next phase.

