// GET /api/debug-github-token
// Debug route: returns the GitHub OAuth token from Clerk for the current user.
// DELETE THIS ROUTE after investigation.

import { auth, clerkClient } from "@clerk/nextjs/server";

export async function GET() {
  const { userId } = await auth();
  if (!userId) {
    return Response.json({ error: "unauthorized" }, { status: 401 });
  }

  const clerk = await clerkClient();

  const [oauthTokens] = await clerk.users.getUserOauthAccessToken(
    userId,
    "github"
  );

  return Response.json({
    userId,
    oauthToken: oauthTokens ?? null,
  });
}

